// Safe JSON parse with markdown fence stripping
const raw = $json.output[0].content[0].text
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  throw new Error('JSON parse failed: ' + raw.substring(0, 200));
}

const sessionId = 'S' + Date.now();

// Return each topic as a separate item with a shared sessionId
return parsed.topics.map(t => ({
  json: {
    id: sessionId + '_' + t.id,
    session_id: sessionId,
    topic_number: t.id,
    title: t.title,
    description: t.description,
    status: 'topic_generated',
    created_at: new Date().toISOString(),
    image_generated: 'false'
  }
}));

const allItems = $input.all();

const topicLines = allItems.map(item => {
  // After Sheets save, field is 'topic' not 'title'
  // Extract number from id e.g. "S1234567890_3" → "3"
  const num = item.json.id ? item.json.id.split('_')[1] : '?';
  const title = item.json.topic || item.json.title || 'Unknown';
  const desc = item.json.description || '';

  return `${num}. *${title}*\n_${desc}_`;
}).join('\n\n');

const message = `🔥 *Today's Trending AI Topics:*\n\n${topicLines}\n\n✅ Reply with topic number(s) to generate content.\nExamples:\n• Single: \`1\`\n• Multiple: \`1,3\``;

return [{ json: { message, items: allItems.map(i => i.json) } }];

// Route incoming Telegram messages by intent
// Returns: { intent, payload, raw_text }

const text = ($json.message?.text || '').trim();
const lc = text.toLowerCase();

let intent = 'unknown';
let payload = {};

if (/^\d+(,\d+)*$/.test(text)) {
  // Topic selection: "1" or "1,3"
  intent = 'topic_selection';
  payload = { selected_ids: text.split(',').map(n => n.trim()) };
} else if (/^approve\s+\S+/i.test(text)) {
  // Content approval: "approve S1234567890_1"
  intent = 'approve_content';
  payload = { content_id: text.split(/\s+/)[1] };
} else if (/^post\s+\S+/i.test(text)) {
  // Final post approval: "post S1234567890_1"
  intent = 'post_to_linkedin';
  payload = { content_id: text.split(/\s+/)[1] };
} else if (/^reject\s+\S+/i.test(text)) {
  // Reject: "reject S1234567890_1"
  intent = 'reject';
  payload = { content_id: text.split(/\s+/)[1] };
}

return [{ json: { intent, payload, raw_text: text, chat_id: $json.message?.chat?.id } }];

// Match selected topic numbers to latest session rows in the sheet
// Selected IDs are topic_numbers (1, 2, 3...) from today's session

const routeData = $('Route by Intent').first().json;
const selectedNumbers = routeData.payload.selected_ids; // e.g. ['1','3']

const allRows = $input.all();

// Find most recent rows for today (get the latest session by created_at)
const rowsWithTopic = allRows.filter(r => r.json.status === 'topic_generated');

// Get the latest session_id by sorting created_at descending
const sorted = [...rowsWithTopic].sort((a, b) =>
  new Date(b.json.created_at) - new Date(a.json.created_at)
);

// Grab the session_id from the most recent topic
const latestSession = sorted[0]?.json?.id?.split('_')[0];

if (!latestSession) throw new Error('No topic_generated rows found. Run Workflow 1 first.');

// Filter to selected topic numbers from the latest session
const matched = rowsWithTopic.filter(r => {
  const [session, num] = r.json.id.split('_');
  return session === latestSession && selectedNumbers.includes(String(num));
});

if (matched.length === 0) throw new Error('No matching topics found for: ' + selectedNumbers.join(','));

return matched.map(item => ({ json: item.json }));

// Safe parse content and merge with topic context
// $json here is from Generate Content node output

const raw = $json.output[0].content[0].text
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let content;
try {
  content = JSON.parse(raw);
} catch(e) {
  throw new Error('Content JSON parse failed: ' + raw.substring(0, 300));
}

// Merge with upstream topic data from Match Selected Topics
const topicData = $('Match Selected Topics').item.json;

return [{
  json: {
    id: topicData.id,
    topic: topicData.topic,
    description: topicData.description,
    linkedin_post: content.linkedin_post || '',
    instagram_caption: content.instagram_caption || '',
    hashtags: content.hashtags || '',
    image_type: content.image_type || '',      // ADD THIS
    image_prompt: content.image_prompt || '',
    status: 'content_generated',
    updated_at: new Date().toISOString()
  }
}];

// Validate: ensure status is content_generated before proceeding
const rows = $input.all();
const row = rows[0]?.json;

if (!row) throw new Error('Row not found for that ID.');
if (row.status !== 'content_generated') {
  throw new Error(`Cannot approve image: status is '${row.status}', expected 'content_generated'.`);
}
if (!row.image_prompt) throw new Error('No image_prompt found for this row.');

return [{ json: row }];

