const posts = $json.data?.children || [];

const headlines = posts
  .filter(p => !p.data.stickied) // remove pinned mod posts
  .slice(0, 10)
  .map(p => ({
    title: p.data.title,
    subreddit: p.data.subreddit,
    score: p.data.score
  }));

if (headlines.length === 0) {
  throw new Error('No Reddit posts found. Check the URL or subreddits.');
}

const headlineText = headlines
  .map((h, i) => `${i + 1}. [r/${h.subreddit}] ${h.title}`)
  .join('\n');

return [{ json: { headlines: headlineText } }];

const articles = $json.articles || [];

const headlines = articles
  .slice(0, 5)
  .map((a, i) => `${i + 1}. ${a.title} (${a.source.name})`)
  .join('\n');

return [{ json: { headlines } }];
